import { Anthropic } from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: process.env.ANTHROPIC_KEY });

async function voiceAgentLoop(transcript: string, history: any[]) {
  const msg = await client.messages.create({
    model: 'claude-3-5-sonnet-20240620',
    max_tokens: 1024,
    messages: [...history, { role: 'user', content: transcript }],
    tools: [{ name: 'get_weather', input_schema: { type: 'object', properties: { city: {type:'string'} } } }]
  });

  // Handle tool results and TTS
  const response = await processTools(msg);
  await elevenLabs.speak(response.text);
  return response;
}

async function monitoredTTS(text: string, startTime: number) {
  const latency = Date.now() - startTime;
  if (latency > 300) {
    console.error('Latency violation:', latency);
    return playFallback('Processing...');
  }

  const audio = await elevenLabs.textToSpeech(text);
  speaker.play(audio);
  return { text, latency };
}

