async function safeVoiceResponse(claudeMsg: any, history: any[]) {
  const result = await verify(claudeMsg.content[0].text, {
    assertions: [
      { type: 'safety', provider: 'vex/moderation', threshold: 0.95 },
      { type: 'latency', max: 300 },
      { type: 'intent_alignment', reference: history[history.length-1] },
      { type: 'no_screen_manipulation' } // Block computer use risks
    ],
    timeout: 50
  });

  return result.passed ? result.response : 'I need a moment to process that.';
